export const isCrisisMessage = (text) => {
  const crisisKeywords = [
    "commit suicide",
    "kill myself",
    "want to die",
    "end my life",
    "no reason to live",
    "hurt myself",
    "self harm",
    "suicide",
    "die"
  ];

  const lower = text.toLowerCase();
  return crisisKeywords.some(word => lower.includes(word));
};
